- (UIImage *)loadImage:(NSString *)name {
    if (!name || name.length == 0) return nil;
    UIImage *img = [UIImage imageNamed:name];
    if (img) return img;

    // Try full path
    if ([name hasPrefix:@"/"]) {
        img = [UIImage imageWithContentsOfFile:name];
        if (img) return img;
    }

    // Try in avatars dir
    NSString *path = [[ChatStorage avatarsDirPath] stringByAppendingPathComponent:name];
    img = [UIImage imageWithContentsOfFile:path];
    return img;
}

#pragma mark - Actions

- (void)bgButtonTapped:(UIButton *)sender {
    self.selectedBgIndex = sender.tag;
    [self updateSelectionState];
}

- (void)colorButtonTapped:(UIButton *)sender {
    self.selectedColorIndex = sender.tag;
    [self updateSelectionState];
}

- (void)avatarRowTapped:(UITapGestureRecognizer *)gesture {
    NSInteger tag = gesture.view.tag;
    self.isEditingMyAvatar = (tag == 1001);

    UIAlertController *sheet = [UIAlertController alertControllerWithTitle:nil message:nil preferredStyle:UIAlertControllerStyleActionSheet];

    __weak typeof(self) weakSelf = self;

    // Take Photo
    [sheet addAction:[UIAlertAction actionWithTitle:@"拍照" style:UIAlertActionStyleDefault handler:^(UIAlertAction * _Nonnull action) {
        __strong typeof(weakSelf) self = weakSelf;
        if (!self) return;
        if (![UIImagePickerController isSourceTypeAvailable:UIImagePickerControllerSourceTypeCamera]) {
            UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"相机不可用" message:@"此设备不支持相机" preferredStyle:UIAlertControllerStyleAlert];
            [alert addAction:[UIAlertAction actionWithTitle:@"确定" style:UIAlertActionStyleCancel handler:nil]];
            [self presentViewController:alert animated:YES completion:nil];
            return;
        }
        UIImagePickerController *picker = [[UIImagePickerController alloc] init];
        picker.sourceType = UIImagePickerControllerSourceTypeCamera;
        picker.delegate = self;
        picker.allowsEditing = YES;
        [self presentViewController:picker animated:YES completion:nil];
    }]];

    // 从相册选择
    [sheet addAction:[UIAlertAction actionWithTitle:@"从相册选择" style:UIAlertActionStyleDefault handler:^(UIAlertAction * _Nonnull action) {
        __strong typeof(weakSelf) self = weakSelf;
        if (!self) return;
        UIImagePickerController *picker = [[UIImagePickerController alloc] init];
        picker.sourceType = UIImagePickerControllerSourceTypePhotoLibrary;
        picker.delegate = self;
        picker.allowsEditing = YES;
        [self presentViewController:picker animated:YES completion:nil];
    }]];

    [sheet addAction:[UIAlertAction actionWithTitle:@"取消" style:UIAlertActionStyleCancel handler:nil]];

    if (sheet.popoverPresentationController) {
        sheet.popoverPresentationController.sourceView = gesture.view;
        sheet.popoverPresentationController.permittedArrowDirections = UIPopoverArrowDirectionUp | UIPopoverArrowDirectionDown;
    }

    [self presentViewController:sheet animated:YES completion:nil];
}
- (void)updateSelectionState {
    for (UIButton *btn in self.bgButtons) {
        UIImageView *check = [btn viewWithTag:100];
        check.hidden = (btn.tag != self.selectedBgIndex);
    }

    for (UIButton *btn in self.colorButtons) {
        UIImageView *check = [btn viewWithTag:100];
        check.hidden = (btn.tag != self.selectedColorIndex);
    }
}

- (void)keyboardDoneTapped {
    [self.nameTextField resignFirstResponder];
}

