#import "ContactViewController.h"
#import "ChatItemModel.h"
#import "ChatStorage.h"
#import "ContactTableViewCell.h"
#import "AddViewController.h"
#import "TalkViewController.h"
#import "ChatMenuView.h"

@interface ContactViewController () <UITableViewDataSource, UITableViewDelegate>

@property (nonatomic, strong) UIBarButtonItem *addChatBarItem;
@property (nonatomic, strong) UITableView *tableView;
@property (nonatomic, assign) BOOL isEditingMode; // 是否处于编辑模式
@property (nonatomic, strong) NSMutableArray<ChatItemModel *> *chatItems;
@property (nonatomic, strong) NSMutableSet<NSString *> *selectedChatIds;  // 选中的chatId集合
@property (nonatomic, strong) UIButton *bottomDeleteButton;  // 底部删除按钮

@end

@implementation ContactViewController

- (instancetype)init {
    self = [super init];
    if (self) {
        self.selectedChatIds = [NSMutableSet set];
    }
    return self;
}

- (void)viewDidLoad {
    [super viewDidLoad];
    self.navigationItem.rightBarButtonItem = self.addChatBarItem;
    [self setupUI];
    [self setupBottomDeleteButton];

    // 预设聊天，并加载与整理顺序
    [ChatStorage ensureDefaultChatsExist];
    [self loadChatData];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(onContactsChanged:) name:@"ContactsChanged" object:nil];
}

- (void)loadChatData {
    self.chatItems = [ChatStorage loadChatList];
    NSArray *orderedTitles = @[@"Emotion", @"Constellation", @"Music"];
    NSDictionary *orderMap = @{ orderedTitles[0]: @0,
                                orderedTitles[1]: @1,
                                orderedTitles[2]: @2,
    };
    [self.chatItems sortUsingComparator:^NSComparisonResult(ChatItemModel * _Nonnull a, ChatItemModel * _Nonnull b) {
        NSNumber *oa = orderMap[a.title ?: @""] ?: @100;
        NSNumber *ob = orderMap[b.title ?: @""] ?: @100;
        return [oa compare:ob];
    }];
    [self.tableView reloadData];
}

- (void)viewDidDisappear:(BOOL)animated {
    [super viewDidDisappear:animated];
    if (self.isEditingMode) {
        [self exitEditMode];
    }
}

- (void)dealloc {
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}


#pragma mark - setup UI

- (void)setupUI {
    self.view.backgroundColor = RGB(234, 234, 234);
    [self addAllSubviews];
    [self addAllConstraints];
}

- (void)addAllSubviews {
    [self.view addSubview:self.tableView];
}

- (void)addAllConstraints {
    [_tableView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.equalTo(self.view);
    }];
}

- (void)setupBottomDeleteButton {
    _bottomDeleteButton = [UIButton buttonWithType:UIButtonTypeCustom];
    [_bottomDeleteButton setImage:[UIImage systemImageNamed:@"trash"] forState:UIControlStateNormal];
    _bottomDeleteButton.tintColor = [UIColor whiteColor];
    _bottomDeleteButton.backgroundColor = RGB(255, 59, 48);
    _bottomDeleteButton.layer.cornerRadius = ZOOM(25);
    _bottomDeleteButton.alpha = 0.0;
    [_bottomDeleteButton addTarget:self action:@selector(confirmDeleteSelected) forControlEvents:UIControlEventTouchUpInside];
    [self.view addSubview:_bottomDeleteButton];

    [_bottomDeleteButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerX.equalTo(self.view);
        make.bottom.equalTo(self.view.mas_safeAreaLayoutGuideBottom).offset(-ZOOM(20));
        make.width.height.mas_equalTo(ZOOM(50));
    }];
}


#pragma mark - UITableViewDataSource

- (NSInteger)tableView:(UITableView *)tableView numberOfRowsInSection:(NSInteger)section {
    return self.chatItems.count;
}

- (UITableViewCell *)tableView:(UITableView *)tableView cellForRowAtIndexPath:(NSIndexPath *)indexPath {
    static NSString *cellIdentifier = @"ContactCell";
    ContactTableViewCell *cell = [tableView dequeueReusableCellWithIdentifier:cellIdentifier];
    if (!cell) {
        cell = [[ContactTableViewCell alloc] initWithStyle:UITableViewCellStyleDefault reuseIdentifier:cellIdentifier];
    }
    cell.backgroundColor = CLEAR_COLOR;
    ChatItemModel *item = self.chatItems[indexPath.row];
    UIImage *avatarImage;
    if (item.avatarPath.length > 0) {
        NSString *absPath = [ChatStorage avatarPathForChatId:item.chatId];
        UIImage *img = [UIImage imageWithContentsOfFile:absPath];
        avatarImage = img ?: [UIImage imageNamed:@"A_avatar_5"];
    } else {
        NSString *iconName = item.icon.length ? item.icon : @"A_avatar_5";
        avatarImage = [UIImage imageNamed:iconName] ?: [UIImage imageNamed:@"A_avatar_5"];
    }


    [cell configureWithAvatar:avatarImage name:item.title subtitle:item.subtitle];
    NSArray *orderedTitles = @[@"Emotion", @"Constellation", @"Music"];
    NSSet *defaultSet = [NSSet setWithArray:orderedTitles];
    BOOL deletable = ![defaultSet containsObject:(item.title ?: @"")];
    [cell setEditingMode:self.isEditingMode deletable:deletable animated:NO];

    // 恢复选中状态
    BOOL isSelected = [self.selectedChatIds containsObject:item.chatId];
    [cell setSelected:isSelected forDeletion:YES];

    // 设置选择框点击回调
    __weak typeof(self) weakSelf = self;
    cell.checkboxTapped = ^{
        [weakSelf toggleSelectionForChatId:item.chatId];
    };

    return cell;
}


#pragma mark - UITableViewDelegate

- (CGFloat)tableView:(UITableView *)tableView heightForRowAtIndexPath:(NSIndexPath *)indexPath {
    return ZOOM(82);
}

- (void)tableView:(UITableView *)tableView didSelectRowAtIndexPath:(NSIndexPath *)indexPath {
    [tableView deselectRowAtIndexPath:indexPath animated:YES];

    if (self.isEditingMode) {
        // 编辑模式下点击行也可以切换选中状态
        if (indexPath.row < self.chatItems.count) {
            ChatItemModel *item = self.chatItems[indexPath.row];
            NSArray *orderedTitles = @[@"Emotion", @"Constellation", @"Music"];
            NSSet *defaultSet = [NSSet setWithArray:orderedTitles];
            BOOL deletable = ![defaultSet containsObject:(item.title ?: @"")];
            if (deletable) {
                [self toggleSelectionForChatId:item.chatId];
            }
        }
        return;
    }

    if (indexPath.row >= self.chatItems.count) { return; }
    ChatItemModel *item = self.chatItems[indexPath.row];
    TalkViewController *vc = [[TalkViewController alloc] init];
    vc.chatId = item.chatId;
    vc.title = item.title ?: @"Chat";
    vc.hidesBottomBarWhenPushed = YES;
    [self.navigationController pushViewController:vc animated:YES];
}


#pragma mark - events

- (void)showAddMenu {
    ChatMenuView *menuView = [[ChatMenuView alloc] init];
    __weak typeof(self) weakSelf = self;
    menuView.onAddChat = ^{
        [weakSelf addChat];
    };
    menuView.onDelete = ^{
        [weakSelf enterEditMode];
    };
    [menuView showInView:self.view belowItem:self.addChatBarItem];
}

- (void)addChat {
    AddViewController *addVC = [[AddViewController alloc] init];
    __weak typeof(self) weakSelf = self;
    addVC.onConfirm = ^(NSString *title, UIImage * _Nullable avatarImage) {
        __strong typeof(weakSelf) self = weakSelf;
        if (!self) return;
        NSDateFormatter *fmt = [[NSDateFormatter alloc] init];
        fmt.locale = [NSLocale localeWithLocaleIdentifier:@"zh_CN"];
        fmt.dateFormat = @"HH:mm";
        NSString *now = [fmt stringFromDate:[NSDate date]];

        ChatItemModel *item = [[ChatItemModel alloc] init];
        item.chatId = [[NSUUID UUID] UUIDString];
        item.title = title.length ? title : @"New Chat";
        item.subtitle = @"Hello, welcome to chat";
        item.time = now ?: @"";
        item.icon = avatarImage ? nil : @"A_avatar_5";

        if (avatarImage) {
            NSString *abs = [ChatStorage avatarPathForChatId:item.chatId];
            NSData *png = UIImagePNGRepresentation(avatarImage);
            [png writeToFile:abs atomically:YES];
            item.avatarPath = [NSString stringWithFormat:@"avatars/%@.png", item.chatId];
        }

        // 加入到预设项之后
        NSArray *orderedTitles = @[@"Emotion", @"Constellation", @"Music"];
        NSDictionary *orderMap = @{ orderedTitles[0]: @0,
                                    orderedTitles[1]: @1,
                                    orderedTitles[2]: @2,
        };
        [self.chatItems addObject:item];
        [self.chatItems sortUsingComparator:^NSComparisonResult(ChatItemModel * _Nonnull a, ChatItemModel * _Nonnull b) {
            NSNumber *oa = orderMap[a.title ?: @""] ?: @100;
            NSNumber *ob = orderMap[b.title ?: @""] ?: @100;
            return [oa compare:ob];
        }];

        [ChatStorage saveChatList:self.chatItems];
        NSMutableArray<ChatItemModel *> *contacts = [ChatStorage loadContacts];
        [contacts addObject:item];
        [ChatStorage saveContacts:contacts];
        [self.tableView reloadData];
        [self dismissViewControllerAnimated:YES completion:nil];
    };
    UINavigationController *nav = [[UINavigationController alloc] initWithRootViewController:addVC];
    nav.modalPresentationStyle = UIModalPresentationFullScreen;
    nav.navigationBarHidden = NO;
    [self presentViewController:nav animated:YES completion:nil];
}

- (void)enterEditMode {
    NSArray *orderedTitles = @[@"Emotion", @"Constellation", @"Music"];
    NSSet *defaultSet = [NSSet setWithArray:orderedTitles];
    NSInteger deletableCount = 0;
    for (ChatItemModel *m in self.chatItems) {
        if (![defaultSet containsObject:(m.title ?: @"")]) {
            deletableCount++;
        }
    }
    if (deletableCount == 0) {
        [SVProgressHUD showInfoWithStatus:@"No contacts to delete"];
        return;
    }

    self.isEditingMode = YES;
    [self.selectedChatIds removeAllObjects];

    [UIView animateWithDuration:0.3 animations:^{
        self.bottomDeleteButton.alpha = 1.0;
    }];

    [self.tableView reloadData];
}

- (void)exitEditMode {
    self.isEditingMode = NO;
