    [alert addAction:[UIAlertAction actionWithTitle:@"Cancel" style:UIAlertActionStyleCancel handler:nil]];
    [alert addAction:[UIAlertAction actionWithTitle:@"Delete" style:UIAlertActionStyleDestructive handler:^(UIAlertAction *action) {
        [self deleteSelectedChats];
    }]];

    [self presentViewController:alert animated:YES completion:nil];
}

- (void)deleteSelectedChats {
    NSArray *orderedTitles = @[@"Emotion", @"Constellation", @"Music"];
    NSSet *defaultSet = [NSSet setWithArray:orderedTitles];

    NSMutableArray *toRemove = [NSMutableArray array];
    for (ChatItemModel *item in self.chatItems) {
        if ([self.selectedChatIds containsObject:item.chatId] && ![defaultSet containsObject:(item.title ?: @"")]) {
            [toRemove addObject:item];
        }
    }

    for (ChatItemModel *item in toRemove) {
        if (item.avatarPath.length > 0) {
            NSString *abs = [ChatStorage avatarPathForChatId:item.chatId];
            [[NSFileManager defaultManager] removeItemAtPath:abs error:nil];
        }
        [ChatStorage clearMessagesForChatId:item.chatId];
        [self.chatItems removeObject:item];
    }

    [ChatStorage saveChatList:self.chatItems];
    [self exitEditMode];
}

