- (void)imagePickerController:(UIImagePickerController *)picker didFinishPickingMediaWithInfo:(NSDictionary<UIImagePickerControllerInfoKey,id> *)info {
    UIImage *image = info[UIImagePickerControllerEditedImage] ?: info[UIImagePickerControllerOriginalImage];
    if (!image) {
        [picker dismissViewControllerAnimated:YES completion:nil];
        return;
    }

    // Resize if needed to save space? For now keep as is.

    if (self.isEditingMyAvatar) {
        self.myAvatarImageView.image = image;

        // Save to file: Use a timestamp to avoid caching issues and ensure uniqueness
        NSString *filename = [NSString stringWithFormat:@"my_avatar_%lld.png", (long long)([[NSDate date] timeIntervalSince1970] * 1000)];
        NSString *path = [[ChatStorage avatarsDirPath] stringByAppendingPathComponent:filename];
        [UIImagePNGRepresentation(image) writeToFile:path atomically:YES];

        // Update setting
        [ChatStorage setMyAvatar:filename];

    } else {
        self.otherAvatarImageView.image = image;

        if (self.chatItem) {
            // Save to file: Use chatId + timestamp to avoid caching
            NSString *filename = [NSString stringWithFormat:@"%@_%lld.png", self.chatItem.chatId, (long long)([[NSDate date] timeIntervalSince1970] * 1000)];
            NSString *path = [[ChatStorage avatarsDirPath] stringByAppendingPathComponent:filename];

            [UIImagePNGRepresentation(image) writeToFile:path atomically:YES];

            // Update model in memory (will be saved in handleComplete)
            self.chatItem.icon = filename;
            self.chatItem.avatarPath = nil; // Clear legacy path to ensure icon is used
        }
    }

    [picker dismissViewControllerAnimated:YES completion:nil];
}

